import { Inference, Page } from "../../../v1/parsing/common/index.js";
import { CropperV1Document } from "./cropperV1Document.js";
import { CropperV1Page } from "./cropperV1Page.js";
/**
 * Cropper API version 1 inference prediction.
 */
export class CropperV1 extends Inference {
    constructor(rawPrediction) {
        super(rawPrediction);
        /** The endpoint's name. */
        this.endpointName = "cropper";
        /** The endpoint's version. */
        this.endpointVersion = "1";
        /** The document's pages. */
        this.pages = [];
        this.prediction = new CropperV1Document();
        rawPrediction["pages"].forEach((page) => {
            if (page.prediction !== undefined && page.prediction !== null &&
                Object.keys(page.prediction).length > 0) {
                this.pages.push(new Page(CropperV1Page, page, page["id"], page["orientation"]));
            }
        });
    }
}
